 "st.4": "der Standard-Port und das Jahr",
 "proto.tag": "Interoperabilität",
 "proto.h2": "Spricht jedes Protokoll, das zählt",
 "proto.openai": "Direkt einsetzbar unter <span class=\"mono\">/v1/chat/completions</span>, dazu Modelle, Embeddings, Runs und Sitzungen — richte vorhandene Clients einfach auf Jikji aus.",
 "proto.mcp": "Model-Context-Protocol-Server und -Client über stdio — nutze MCP-Werkzeuge oder stelle Jikji selbst als eines bereit.",
 "proto.acp": "Agent Communication Protocol über stdio für lokale, prozessbasierte Agent-Partner.",
 "proto.a2a": "Zusammenarbeit zwischen Agenten — Aufgaben verteilen, delegieren und Ergebnisse zwischen Agenten einsammeln.",
 "ops.h": "Werkzeuge für den Betrieb",
 "ops.p": "<span class=\"mono\">jikjictl</span> deckt Zugangsdaten und Tresor, RBAC, Richtlinien, Audit-Abfragen, Tracing, Nutzung und einen Marktplatz ab — dazu ein separates Web-Dashboard, das niemals Schlüssel auf dem Server ablegt.",
 "term.h": "Im Terminal zu Hause",
 "term.p": "Interaktiver TUI-Chat, Einzel-Prompt-Modus, JSONL-Event-Streams für die Automatisierung und ein MCP-konformer JSON-RPC-Modus — Agenten, die sich per Pipe verketten lassen.",
 "test.h": "Getestet wie Infrastruktur",
 "test.p": "Ein deterministisches <span class=\"mono\">make verify</span>-Gate plus abgesicherte Live-Smoke-Tests gegen echte Anbieter. Benchmark-, Fuzz-, Property- und Concurrency-Tests durchziehen die gesamte Codebasis.",
 "nav.start": "Jetzt loslegen",
 "start.h2": "In unter einer Minute startklar",
 "cm1": "den Server starten (Standard-Port 1377 — ja, genau dieses 1377)",
 "cm2": "die lokale Umgebung prüfen",
